// === CONFIG: remplace par les noms exacts de tes nodes ===
const NODE_ITEMS = 'ItemsID';             // node qui sort increment, ItemsID, item i, No Article i, Criticité i, Name item i, Procédé i, Consommable i
const NODE_PO_CREATE = 'Create PO page';  // node Notion qui a créé la page PO (pour récupérer son id)

// === UTILITAIRES ===
const SAFE_BATCH = 90;
function chunk(arr, size) { const out=[]; for (let i=0;i<arr.length;i+=size) out.push(arr.slice(i,i+size)); return out; }

function buildHeadingExact(text) {
  return {
    object: "block",
    type: "heading_2",
    heading_2: { rich_text: [{ type: "text", text: { content: text } }], is_toggleable: false }
  };
}

// Achât — 3 colonnes : 1) lien consommable (mention page), 2) item i, 3) "Criticité : <valeur>" si non vide
function buildToDoAchat(relId, label, criticite, fallbackFirstColText) {
  const rt = [];

  // Colonne 1 : lien consommable (mention page si possible)
  if (relId) {
    rt.push({ type: "mention", mention: { type: "page", page: { id: relId } } });
  } else if (fallbackFirstColText && String(fallbackFirstColText).trim() !== '') {
    rt.push({ type: "text", text: { content: String(fallbackFirstColText).trim() } });
  } else {
    rt.push({ type: "text", text: { content: " " } });
  }

  // Colonne 2 : item (i)
  const col2 = (label && String(label).trim()) ? String(label).trim() : '';
  if (col2 !== '') {
    rt.push({ type: "text", text: { content: " — " } });
    rt.push({ type: "text", text: { content: col2 } });
  }

  // Colonne 3 : "Criticité : <valeur>" uniquement si valeur non vide
  const c = (criticite !== null && criticite !== undefined) ? String(criticite).trim() : '';
  if (c !== '') {
    rt.push({ type: "text", text: { content: " — " } });
    rt.push({ type: "text", text: { content: "Criticité : " } });
    rt.push({ type: "text", text: { content: c } });
  }

  return { object: "block", type: "to_do", to_do: { rich_text: rt, checked: false } };
}

// Ligne sous Achât : "<NoArticle | Lien i> -> URL" ; si NoArticle vide, utiliser "Lien i"
function buildAchatLinkLine(i, noArticle, url) {
  const u = (url && String(url).trim() !== '') ? String(url).trim() : '';
  if (u === '') return null;
  const art = (noArticle !== null && noArticle !== undefined) ? String(noArticle).trim() : '';
  const label = (art !== '') ? art : `Lien ${i}`;
  return {
    object: "block",
    type: "paragraph",
    paragraph: {
      rich_text: [
        { type: "text", text: { content: `${label} -> ` } },
        { type: "text", text: { content: u, link: { url: u } } }
      ]
    }
  };
}

// Reception — 2 colonnes : 1) Name item i, 2) Procédé i (si non vide)
function buildToDoReception(nameItem, procede) {
  const rt = [];
  const col1 = (nameItem && String(nameItem).trim()) ? String(nameItem).trim() : '';
  const col2 = (procede && String(procede).trim()) ? String(procede).trim() : '';
  if (col1 !== '') rt.push({ type: "text", text: { content: col1 } });
  if (col2 !== '') {
    if (rt.length > 0) rt.push({ type: "text", text: { content: " — " } });
    rt.push({ type: "text", text: { content: col2 } });
  }
  if (rt.length === 0) rt.push({ type: "text", text: { content: " " } });
  return { object: "block", type: "to_do", to_do: { rich_text: rt, checked: false } };
}

// Ligne sous Reception : valeur seule de "Consommable i" (sans libellé)
function buildConsommableValueLine(value) {
  const v = (value !== null && value !== undefined) ? String(value).trim() : '';
  if (v === '') return null;
  return { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: v } }] } };
}

// === RÉCUP DES DONNÉES EN AMONT ===
const itemsNodeItems = $(NODE_ITEMS).all();
if (!itemsNodeItems.length) throw new Error('Aucun output du node ItemsID');
const base = itemsNodeItems[0].json;

const poCreate = $(NODE_PO_CREATE).item.json || {};
const poId = poCreate.id || base.po_page_id;
if (!poId) throw new Error('ID de la page PO introuvable. Vérifie NODE_PO_CREATE.id ou base.po_page_id');

// === NOMBRE D’ITEMS & IDs de pages consommables ===
const ids = (base.ItemsID || '').split(',').map(s => s.trim()).filter(Boolean);
let inc = Number(base.increment) || 0;
if (!inc) {
  const itemKeys = Object.keys(base).filter(k => /^item\s+\d+$/i.test(k));
  inc = Math.max(ids.length, itemKeys.length, 0);
}

// === CONSTRUCTION DES BLOCS ===
const blocks = [];

// Titres EXACTS
blocks.push(buildHeadingExact('Achât'));

for (let i = 1; i <= inc; i++) {
  const label       = base[`item ${i}`];                         // "35 X 56.00$"
  const criticite   = base[`Criticité ${i}`] ?? base[`Criticié ${i}`]; // garder vide si absent
  const noArticle   = base[`No Article ${i}`];
  const nameItem    = base[`Name item ${i}`];
  const url         = base[`Lien ${i}`] || null;
  const relId       = ids[i - 1] || null;

  // Achât — to_do (3 colonnes, Criticité avec son libellé si présent)
  const firstColFallback = nameItem || '';
  blocks.push(buildToDoAchat(relId, label, criticite ?? '', firstColFallback));

  // Sous Achât : "<NoArticle | Lien i> -> URL" (si URL présent)
  const linkLine = buildAchatLinkLine(i, noArticle, url);
  if (linkLine) blocks.push(linkLine);
}

blocks.push(buildHeadingExact('Reception'));

for (let i = 1; i <= inc; i++) {
  const nameItem    = base[`Name item ${i}`] ?? '';
  const procede     = base[`Procédé ${i}`] ?? '';
  const consommable = base[`Consommable ${i}`] ?? '';

  // Reception — to_do (2 colonnes)
  blocks.push(buildToDoReception(nameItem, procede));

  // Sous Reception : valeur de Consommable i (sans libellé)
  const consLine = buildConsommableValueLine(consommable);
  if (consLine) blocks.push(consLine);
}

// === BATCHING → 1 item / requête append ===
const batches = chunk(blocks, SAFE_BATCH);
return batches.map(batch => ({ json: { target_id: poId, body: { children: batch } } }));

// Récupérer tous les items d'entrée
const items = $input.all();

if (items.length === 0) {
  return [{ json: { message: "Aucun item à traiter" } }];
}

// Trouver le premier responsable (premier item qui a un responsable défini)
let firstResponsable = null;

for (let item of items) {
  if (item.json.properties && 
      item.json.properties["🔴Responsable achat"] && 
      item.json.properties["🔴Responsable achat"].rich_text && 
      item.json.properties["🔴Responsable achat"].rich_text[0] && 
      item.json.properties["🔴Responsable achat"].rich_text[0].plain_text) {
    firstResponsable = item.json.properties["🔴Responsable achat"].rich_text[0].plain_text;
    break; // Arrêter dès qu'on trouve le premier
  }
}

// Retourner TOUS les items avec une constante booléenne
return items.map((item, index) => {
  // Extraire le responsable de cet item
  let itemResponsable = null;
  if (item.json.properties && 
      item.json.properties["🔴Responsable achat"] && 
      item.json.properties["🔴Responsable achat"].rich_text && 
      item.json.properties["🔴Responsable achat"].rich_text[0] && 
      item.json.properties["🔴Responsable achat"].rich_text[0].plain_text) {
    itemResponsable = item.json.properties["🔴Responsable achat"].rich_text[0].plain_text;
  }

  return {
    json: {
      ...item.json,
      isFirstResponsable: itemResponsable === firstResponsable
    }
  };
});
